export function PlanExecutionView({ plan }: { plan:any }) {
  const steps: any[] = plan.steps ?? [];
  const doneSteps = steps.filter((s: any) => s.state === 'done');
  const failedSteps = steps.filter((s: any) => s.state === 'failed');
  const runningSteps = steps.filter((s: any) => s.state === 'running');
  const pct = steps.length > 0 ? Math.round((doneSteps.length / steps.length) * 100) : 0;
  const planColor = '#c084fc';
  const barWidth = 20;
  const filled = Math.round((doneSteps.length / Math.max(steps.length, 1)) * barWidth);
  const progressBar = '\u2588'.repeat(filled) + '\u2591'.repeat(barWidth - filled);
  return (
    <Box flexDirection="column" paddingLeft={2}>
            <Box>
              <Text color={planColor} bold>{'\u25b8 Plan: '}</Text>
              <Text bold>{plan.intent}</Text>
            </Box>
            <Box>
              <Text color={planColor}>{progressBar}</Text>
              <Text dimColor>{' '}{String(pct)}{'% \u00b7 '}{String(doneSteps.length)}{'/'}{String(steps.length)}{' steps'}</Text>
              {failedSteps.length > 0 && <Text color="red">{' \u00b7 '}{String(failedSteps.length)}{' failed'}</Text>}
              {plan.totalActualCostUsd > 0 && <Text dimColor>{' \u00b7 $'}{plan.totalActualCostUsd.toFixed(4)}</Text>}
            </Box>
            <Text>{' '}</Text>
      {(steps).map((s, i) => {
        const cfg = (STEP_TYPE_CONFIG as any)[s.type] ?? { icon: '?', color: '#888', label: s.type };
        const stateInfo = (STEP_STATE_ICONS as any)[s.state ?? 'pending'] ?? STEP_STATE_ICONS.pending;
        const result = s.result;
        const elapsed = result?.durationMs ? `${(result.durationMs / 1000).toFixed(1)}s` : '';
        const cost = result?.actualCostUsd ? `$${result.actualCostUsd.toFixed(4)}` : '';
        return (
          <React.Fragment key={s.id}>
                    <Box key={s.id}>
                      <Text color={stateInfo.color}>{stateInfo.icon}{' '}</Text>
                      <Box width={3}>
                        <Text bold color="white">{String(i + 1)}{'.'}</Text>
                      </Box>
                      <Text color={cfg.color}>{cfg.icon}{' '}</Text>
                      <Text color={s.state === 'done' ? '#64748b' : s.state === 'running' ? 'white' : undefined}>{s.description.slice(0, 50)}{s.description.length > 50 ? '\u2026' : ''}</Text>
                      {(elapsed || cost) && (
                        <Text dimColor>{' ('}{elapsed}{elapsed && cost ? ', ' : ''}{cost}{')'}</Text>
                      )}
                      {result?.status === 'failure' && result?.error && (
                        <Text color="red">{' \u2014 '}{result.error.slice(0, 40)}</Text>
                      )}
                    </Box>
          </React.Fragment>
        );
      })}
      {runningSteps.length > 0 && (
                <Box marginTop={1}>
                  <Text color="#fbbf24">{'\u25cf Running: '}</Text>
                  <Text>{runningSteps.map((s: any) => s.description).join(', ')}</Text>
                </Box>
      )}
    </Box>
  );
}

